import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import LoginPage from './pages/LoginPage';
import ProblemsPage from './pages/ProblemsPage';
import ProblemSolverPage from './pages/ProblemSolverPage';
import LeaderboardPage from './pages/LeaderboardPage';
import { api } from './services/api';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    checkAuth();
  }, []);

  const checkAuth = async () => {
    const token = localStorage.getItem('token');
    if (token) {
      try {
        await api.getCurrentUser();
        setIsAuthenticated(true);
      } catch (error) {
        localStorage.removeItem('token');
        setIsAuthenticated(false);
      }
    }
    setLoading(false);
  };

  if (loading) {
    return (
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100vh' }}>
        <div>Loading...</div>
      </div>
    );
  }

  return (
    <Router>
      <Routes>
        <Route 
          path="/login" 
          element={!isAuthenticated ? <LoginPage onLogin={() => setIsAuthenticated(true)} /> : <Navigate to="/problems" />} 
        />
        <Route 
          path="/problems" 
          element={isAuthenticated ? <ProblemsPage /> : <Navigate to="/login" />} 
        />
        <Route 
          path="/problem/:id" 
          element={isAuthenticated ? <ProblemSolverPage /> : <Navigate to="/login" />} 
        />
        <Route 
          path="/leaderboard" 
          element={isAuthenticated ? <LeaderboardPage /> : <Navigate to="/login" />} 
        />
        <Route path="/" element={<Navigate to={isAuthenticated ? "/problems" : "/login"} />} />
      </Routes>
    </Router>
  );
}

export default App;
